questions.code:
function withdraw(balance, amount) {
  if (amount > balance) {
    throw new Error("餘額不足");
  }
  return balance - amount;
}

try {
  console.log(withdraw(100, 50));
  console.log(withdraw(50, 80));
  console.log("完成");
} catch (err) {
  console.log("錯誤：" + err.message);
}

